mapper.select:
/* skylifeMapper.getExistMember */
SELECT  COUNT(1)
FROM    MSP_PARTNER_SKYLIFE_MST
WHERE	CONTRACT_NUM = #{contractNum}

mapper.insert:
/* skylifeMapper.insertMemberMst */
INSERT INTO MSP_PARTNER_SKYLIFE_MST (
    CONTRACT_NUM
    , CI
    , BIRTH_DT
    , SVC_OPEN_DT
    , RATE_CD
    , CHG_KIND_CD
    , CHG_DT
) VALUES (
    #{scrbrNo}
    , #{ci}
    , #{birthDh}
    , #{svcOpenDh}
    , #{prdtCd}
    , #{chgKindCd}
    , #{chgDh}
)

		/* skylifeMapper.insertMemberIfHst */
		INSERT INTO MSP_PARTNER_SKYLIFE_IF_HST (
			CONTRACT_NUM
			, EVENT_NO
		    , CI
		    , BIRTH_DT
		    , SVC_OPEN_DT
		    , RSCS_DT
		    , RATE_CD
		    , RATE_NM
		    , CHG_KIND_CD
		    , CHG_DT
		    , SEND_DT
            , REG_DT
		) VALUES (
			#{scrbrNo}
			, (SELECT NVL(MAX(TO_NUMBER(EVENT_NO))+1, 1) FROM MSP_PARTNER_SKYLIFE_IF_HST WHERE CONTRACT_NUM = #{scrbrNo})
		    , #{ci}
		    , #{birthDh}
		    , #{svcOpenDh}
		    , #{rscsDh}
		    , #{prdtCd}
		    , #{prdtNm} 
		    , #{chgKindCd}
		    , #{chgDh}
		    , TO_CHAR(SYSDATE, 'YYYYMMDD')
		    , SYSDATE
		)

mapper.update:
/* skylifeMapper.updateMemberMst */
UPDATE	MSP_PARTNER_SKYLIFE_MST
SET		CI = #{ci}
		, BIRTH_DT = #{birthDh}
		, RSCS_DT = #{rscsDh}
		, RATE_CD = #{prdtCd}
		, CHG_KIND_CD = #{chgKindCd}
		, CHG_DT = #{chgDh}
WHERE	CONTRACT_NUM = #{scrbrNo}
